"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";

const STORAGE_KEY = "tfd-tracker-v2";

export function TrackerClient() {
  const [rawState, setRawState] = useState<string>("");
  const [status, setStatus] = useState<string>("Loading...");
  const [dirty, setDirty] = useState(false);

  useEffect(() => {
    const run = async () => {
      const res = await fetch("/api/state", { cache: "no-store" });
      if (!res.ok) {
        setStatus("Failed to load state.");
        return;
      }
      const data = await res.json();
      setRawState(JSON.stringify(data.state ?? {}, null, 2));
      setStatus("Loaded.");
    };
    run();
  }, []);

  useEffect(() => {
    if (!dirty) return;
    const id = window.setTimeout(async () => {
      try {
        const state = JSON.parse(rawState);
        const res = await fetch("/api/state", {
          method: "PUT",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ state }),
        });
        setStatus(res.ok ? "Saved." : "Save failed.");
        setDirty(false);
      } catch {
        setStatus("Invalid JSON.");
      }
    }, 500);
    return () => window.clearTimeout(id);
  }, [dirty, rawState]);

  const summary = useMemo(() => {
    try {
      const parsed = JSON.parse(rawState);
      return {
        reactors: (parsed.reactors ?? []).length,
        weapons: (parsed.weapons ?? []).length,
        descendants: (parsed.descendants ?? []).length,
        materials: (parsed.materials ?? []).length,
      };
    } catch {
      return null;
    }
  }, [rawState]);

  async function importLocalStorage() {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      setStatus("No local data found in this browser.");
      return;
    }
    try {
      const state = JSON.parse(raw);
      const res = await fetch("/api/state/import", {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ state }),
      });
      if (!res.ok) {
        setStatus("Import failed.");
        return;
      }
      setRawState(JSON.stringify(state, null, 2));
      setStatus("Imported local browser data.");
    } catch {
      setStatus("Import failed due to invalid local JSON.");
    }
  }

  return (
    <main style={{ maxWidth: 1100, margin: "1rem auto", padding: "1rem" }}>
      <h1>TFD Tracker (Cloud Save)</h1>
      <p style={{ opacity: 0.8 }}>
        Data is private to your Discord account. This editor is a migration-safe bridge while UI endpoints are being
        fully wired.
      </p>
      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", margin: "0.75rem 0" }}>
        <button onClick={importLocalStorage}>Import local browser data</button>
        <Link href="/api/auth/signout">Sign out</Link>
      </div>
      {summary && (
        <p style={{ opacity: 0.85 }}>
          Reactors: {summary.reactors} | Weapons: {summary.weapons} | Descendants: {summary.descendants} | Materials:{" "}
          {summary.materials}
        </p>
      )}
      <p>{status}</p>
      <textarea
        style={{ width: "100%", minHeight: 520, fontFamily: "monospace", fontSize: 13, padding: 12 }}
        value={rawState}
        onChange={(e) => {
          setRawState(e.target.value);
          setDirty(true);
          setStatus("Editing...");
        }}
      />
    </main>
  );
}
